// AUTO-GENERATED DRAFT SCREEN: NotificationCategoriesScreen
import React, { useState, useEffect, useCallback } from 'react';
import { Switch } from '@/components/ui/switch'; // Assuming shadcn/ui switch
import { Label } from '@/components/ui/label'; // Assuming shadcn/ui label
import { Card, CardHeader, CardContent, CardTitle, CardDescription } from '@/components/ui/card'; // Assuming shadcn/ui card components
import { Button } from '@/components/ui/button'; // Assuming shadcn/ui button

// Placeholder for tRPC hooks and types
// In a real application, these would be generated by tRPC
type NotificationCategory = {
  id: string;
  name: string;
  enabled: boolean;
  description: string;
};

// Mock tRPC hooks for demonstration
const trpc = {
  notification: {
    getCategories: {
      useQuery: (options?: { onError?: (error: any) => void }) => {
        const [data, setData] = useState<NotificationCategory[] | undefined>(undefined);
        const [isLoading, setIsLoading] = useState(true);
        const [isError, setIsError] = useState(false);
        const [error, setError] = useState<any>(null);

        useEffect(() => {
          setIsLoading(true);
          // Simulate API call
          setTimeout(() => {
            if (Math.random() > 0.1) { // Simulate occasional error
              setData([
                { id: '1', name: 'Mentions', enabled: true, description: 'Get notified when someone mentions you.' },
                { id: '2', name: 'Direct Messages', enabled: false, description: 'Receive alerts for private messages.' },
                { id: '3', name: 'System Alerts', enabled: true, description: 'Important updates about your account.' },
              ]);
              setIsError(false);
            } else {
              setIsError(true);
              setError({ message: 'Failed to fetch categories.' });
              options?.onError?.({ message: 'Failed to fetch categories.' });
            }
            setIsLoading(false);
          }, 1000);
        }, []);

        return { data, isLoading, isError, error };
      },
    },
    updateCategory: {
      useMutation: (options?: { onSuccess?: () => void; onError?: (error: any) => void }) => {
        const [isLoading, setIsLoading] = useState(false);
        const [isError, setIsError] = useState(false);
        const [error, setError] = useState<any>(null);

        const mutate = useCallback(async (category: NotificationCategory) => {
          setIsLoading(true);
          setIsError(false);
          setError(null);
          // Simulate API call
          await new Promise(resolve => setTimeout(resolve, 500));
          if (Math.random() > 0.1) { // Simulate occasional error
            options?.onSuccess?.();
          } else {
            setIsError(true);
            setError({ message: `Failed to update ${category.name}.` });
            options?.onError?.({ message: `Failed to update ${category.name}.` });
          }
          setIsLoading(false);
        }, [options?.onSuccess, options?.onError]);

        return { mutate, isLoading, isError, error };
      },
    },
  },
};

const NotificationCategoriesScreen: React.FC = () => {
  const { data: categories, isLoading, isError, error, refetch } = trpc.notification.getCategories.useQuery();
  const { mutate: updateCategoryMutation, isLoading: isUpdating, isError: isUpdateError, error: updateError } = trpc.notification.updateCategory.useMutation({
    onSuccess: () => {
      // In a real app, you might invalidate queries or refetch here
      console.log('Category updated successfully!');
    },
    onError: (err) => {
      console.error('Update error:', err);
    },
  });

  const handleToggle = useCallback((category: NotificationCategory) => {
    updateCategoryMutation({ ...category, enabled: !category.enabled });
  }, [updateCategoryMutation]);

  if (isLoading) {
    return (
      <div className="flex justify-center items-center h-screen dark:bg-gray-900 dark:text-gray-100">
        <p>Loading notification categories...</p>
      </div>
    );
  }

  if (isError) {
    return (
      <div className="flex flex-col justify-center items-center h-screen dark:bg-gray-900 dark:text-gray-100">
        <p className="text-red-500">Error: {error?.message || 'Failed to load categories.'}</p>
        <Button onClick={() => refetch()} className="mt-4">Retry</Button>
      </div>
    );
  }

  return (
    <div className="container mx-auto p-4 dark:bg-gray-900 dark:text-gray-100 min-h-screen">
      <Card className="w-full max-w-2xl mx-auto">
        <CardHeader>
          <CardTitle className="text-2xl font-bold">Notification Categories</CardTitle>
          <CardDescription>Manage your notification preferences for different categories.</CardDescription>
        </CardHeader>
        <CardContent className="space-y-6">
          {categories?.map((category) => (
            <div key={category.id} className="flex items-center justify-between">
              <div className="grid gap-1.5">
                <Label htmlFor={`toggle-${category.id}`} className="text-base font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70">
                  {category.name}
                </Label>
                <p className="text-sm text-gray-500 dark:text-gray-400">
                  {category.description}
                </p>
              </div>
              <Switch
                id={`toggle-${category.id}`}
                checked={category.enabled}
                onCheckedChange={() => handleToggle(category)}
                disabled={isUpdating}
                aria-label={`Toggle ${category.name} notifications`}
              />
            </div>
          ))}
          {isUpdateError && (
            <p className="text-red-500 text-sm mt-4">Update failed: {updateError?.message || 'Please try again.'}</p>
          )}
          {isUpdating && (
            <p className="text-blue-500 text-sm mt-4">Saving changes...</p>
          )}
        </CardContent>
      </Card>
    </div>
  );
};

export default NotificationCategoriesScreen;
